import torch
import torch.distributed as dist
import torch.nn.functional as F


def _world_size():
    if dist.is_available() and dist.is_initialized():
        return dist.get_world_size()
    return 1


def _rank():
    if dist.is_available() and dist.is_initialized():
        return dist.get_rank()
    return 0


class _GatherFromLastDim(torch.autograd.Function):
    """Forward: all_gather local shards and concat along the last dim.
    Backward: return this rank's slice of the incoming gradient.
    """

    @staticmethod
    def forward(ctx, input_):
        world_size = _world_size()
        if world_size == 1:
            return input_
        input_ = input_.contiguous()
        tensor_list = [torch.empty_like(input_) for _ in range(world_size)]
        dist.all_gather(tensor_list, input_)
        return torch.cat(tensor_list, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        world_size = _world_size()
        if world_size == 1:
            return grad_output
        local_size = grad_output.shape[-1] // world_size
        grads = torch.split(grad_output, local_size, dim=-1)
        return grads[_rank()].contiguous()


class _ReduceFromParallelRegion(torch.autograd.Function):
    """Forward: all_reduce (sum) the partial outputs across ranks.
    Backward: identity (the gradient of a sum-reduce w.r.t. each input is 1).
    """

    @staticmethod
    def forward(ctx, input_):
        world_size = _world_size()
        if world_size == 1:
            return input_
        input_ = input_.clone()
        dist.all_reduce(input_)
        return input_

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(torch.nn.Module):
    """Split the weight along the output dimension (columns of the ``X A`` matmul,
    i.e. rows of the PyTorch ``[out_features, in_features]`` weight). Each rank
    computes a shard of the output; forward all_gathers them along the last dim.
    The bias is sharded the same way as the output dimension.
    """

    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world_size = _world_size()
        rank = _rank()
        assert out_features % world_size == 0, \
            "out_features must be divisible by world_size"
        self.in_features = in_features
        self.out_features = out_features
        self.output_size_per_partition = out_features // world_size

        start = rank * self.output_size_per_partition
        end = start + self.output_size_per_partition
        weight_shard = master_weight[start:end, :].clone().detach()
        self.weight = torch.nn.Parameter(weight_shard.contiguous())

        if bias:
            self.bias = torch.nn.Parameter(
                torch.zeros(
                    self.output_size_per_partition,
                    dtype=master_weight.dtype,
                    device=master_weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        local_output = F.linear(input_, self.weight, self.bias)
        return _GatherFromLastDim.apply(local_output)


class RowParallelLinear(torch.nn.Module):
    """Split the weight along the input dimension (rows of the ``X A`` matmul,
    i.e. columns of the PyTorch ``[out_features, in_features]`` weight). Each
    rank's forward receives only its pre-scattered slice of the input; the
    partial outputs are summed via all_reduce. The bias stays full on each rank.
    """

    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world_size = _world_size()
        rank = _rank()
        assert in_features % world_size == 0, \
            "in_features must be divisible by world_size"
        self.in_features = in_features
        self.out_features = out_features
        self.input_size_per_partition = in_features // world_size

        start = rank * self.input_size_per_partition
        end = start + self.input_size_per_partition
        weight_shard = master_weight[:, start:end].clone().detach()
        self.weight = torch.nn.Parameter(weight_shard.contiguous())

        if bias:
            self.bias = torch.nn.Parameter(
                torch.zeros(
                    out_features,
                    dtype=master_weight.dtype,
                    device=master_weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        # input_ is already this rank's slice along the last (input) dimension.
        local_output = F.linear(input_, self.weight)
        output = _ReduceFromParallelRegion.apply(local_output)
        if self.bias is not None:
            output = output + self.bias
        return output
